import { createSlice } from '@reduxjs/toolkit';

const stored = (() => {
  try { return JSON.parse(localStorage.getItem('hireeasy_user')); } catch { return null; }
})();

const authSlice = createSlice({
  name: 'auth',
  initialState: {
    user: stored || null,
    firebaseUser: null,
    isAuthenticated: !!stored,
    loading: true,   // true until Firebase resolves onAuthStateChanged
    error: null,
    redirectAfterLogin: null, // stores path to redirect after login
  },
  reducers: {
    setFirebaseUser: (state, action) => {
      state.firebaseUser = action.payload;
      state.loading = false;
    },
    setUser: (state, action) => {
      state.user = action.payload;
      state.isAuthenticated = !!action.payload;
      if (action.payload) {
        localStorage.setItem('hireeasy_user', JSON.stringify(action.payload));
      } else {
        localStorage.removeItem('hireeasy_user');
      }
    },
    setLoading: (state, action) => { state.loading = action.payload; },
    setError: (state, action) => { state.error = action.payload; },
    setRedirectAfterLogin: (state, action) => { state.redirectAfterLogin = action.payload; },
    logout: (state) => {
      state.user = null;
      state.firebaseUser = null;
      state.isAuthenticated = false;
      state.redirectAfterLogin = null;
      localStorage.removeItem('hireeasy_user');
    },
  },
});

export const {
  setFirebaseUser, setUser, setLoading, setError, setRedirectAfterLogin, logout,
} = authSlice.actions;
export default authSlice.reducer;
